OUTPUT = os.path.join(os.path.dirname(os.path.abspath(__file__)), "coords.json")

coords = {}
if os.path.exists(OUTPUT):
    with open(OUTPUT, "r", encoding="utf-8") as f:
        coords = json.load(f)
    print(f"Resuming: {len(coords)}/{len(STATIONS)} done")

def geocode(query):
    url = "https://nominatim.openstreetmap.org/search?q=" + urllib.parse.quote(query) + "&format=json&limit=1&countrycodes=il"
    req = urllib.request.Request(url, headers={"Accept-Language": "he", "User-Agent": "FuelFinder/2.0"})
    try:
        with urllib.request.urlopen(req, timeout=10) as r:
            data = json.loads(r.read())
            if data:
                return [float(data[0]["lat"]), float(data[0]["lon"])]
    except Exception as e:
        print(f"  Error: {e}")
    return None

total = len(STATIONS)
for i, s in enumerate(STATIONS):
    key = str(i)
    if key in coords:
        continue
    q = s.get("q") or (s["n"] + ", ישראל")
    result = geocode(q)
    coords[key] = result
    done = len(coords)
    status = f"{result[0]:.4f},{result[1]:.4f}" if result else "not found"
    name = (s["n"] or "(no name)")[:30]
    print(f"[{done:3d}/{total}] {name:30s}  {status}")
    if done % 20 == 0:
        with open(OUTPUT, "w", encoding="utf-8") as f:
            json.dump(coords, f, ensure_ascii=False)
    time.sleep(1.2)

with open(OUTPUT, "w", encoding="utf-8") as f:
    json.dump(coords, f, ensure_ascii=False)

found = sum(1 for v in coords.values() if v)
print(f"Done! {found}/{total} stations geocoded. Saved: {OUTPUT}")
